/**
 * External dependencies
 */
import { useState } from '@googleforcreators/react';
import { TransitionGroup } from 'react-transition-group';
import styled, { ThemeProvider } from 'styled-components';
import {
  theme as dsTheme,
  ThemeGlobals,
} from '@googleforcreators/design-system';
/**
 * Internal dependencies
 */
import { TIPS } from '../../../../app/helpCenter/constants';
import { QuickTip as HelpCenterQuickTip } from '..';

export default {
  title: 'Stories Editor/Components/Help Center/Quick Tip',
  args: {
    isLeftToRightTransition: true,
  },
};

const Bg = styled.div`
  position: relative;
  top: 0;
  left: 0;
  background-color: ${({ theme }) => theme.colors.bg.primary};
  padding: 0 50px;
`;

const Container = styled.div`
  position: relative;
  width: 340px;
  height: 100%;
  height: 400px;
  overflow: hidden;
`;

const [tip] = Object.values(TIPS);
export const QuickTip = {
  render: function Render(args) {
    const [toggled, setToggled] = useState(true);
    return (
      <ThemeProvider theme={dsTheme}>
        <ThemeGlobals.Styles />
        <button onClick={() => setToggled((v) => !v)}>{'toggleTips'}</button>
        <Bg>
          <Container>
            <TransitionGroup component={null}>
              <HelpCenterQuickTip
                key={toggled ? 'key1' : 'key2'}
                title={tip.title}
                description={tip.description}
                {...args}
              />
            </TransitionGroup>
          </Container>
        </Bg>
      </ThemeProvider>
    );
  },
};
